-- 2251 productos importados de Lista.csv
-- Los productos de la linea 'Behmont - IMP' quedan en la categoria Importados.
-- El resto queda SIN categoria asignada (category_id NULL) para clasificar manualmente
-- desde /admin/productos, ya que el excel no trae esa informacion.

on conflict (sku) do update set name = excluded.name, price = excluded.price, stock = excluded.stock, brand_id = excluded.brand_id, category_id = excluded.category_id;
